from flask import Flask, jsonify, request
import json

app = Flask(__name__)

@app.after_request
def after_request(response):
    response.headers.add('Access-Control-Allow-Origin', '*')
    response.headers.add('Access-Control-Allow-Headers', 'Content-Type,Authorization')
    response.headers.add('Access-Control-Allow-Methods', 'GET,PUT,POST,DELETE,OPTIONS')
    return response

@app.route('/api/health', methods=['GET', 'OPTIONS'])
def health_check():
    if request.method == 'OPTIONS':
        return jsonify({'status': 'ok'}), 200
    return jsonify({'status': 'ok'}), 200

@app.route('/api/data', methods=['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'])
def handle_data():
    if request.method == 'OPTIONS':
        return jsonify({'message': 'OK'}), 200
    
    if request.method == 'GET':
        return jsonify({'data': 'sample data'}), 200
    elif request.method == 'POST':
        return jsonify({'message': 'Data created', 'received': request.json}), 201
    elif request.method == 'PUT':
        return jsonify({'message': 'Data updated', 'received': request.json}), 200
    elif request.method == 'DELETE':
        return jsonify({'message': 'Data deleted'}), 200

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=8080)